scwin.f_deleteRow = function () {
  if (ds_main4.getCellData(0, "tableFlag") == 306) {
    if (ds_main4.getRowCount() == 1) {
      ds_main4.removeAll();
      ds_main4.reform();
    } else {
      // export ??
      // var dataset = ds_main4.ExportData(2, ds_main4.getRowCount(),true);
      // ds_main4.removeAll();
      // ds_main4.ImportData(dataset);

      const dataset = ds_main4.getAllJSON().slice(1);
      ds_main4.removeAll();
      ds_main4.reform();
      ds_main4.setJSON(dataset);
      ds_main4.reform();
    }
  } else {
    // ds_main4.DeleteMarked();

    // var delArr = ds_main4.getDeletedIndex();
    // for (var i = ds_main4.getRowCount() - 1 ; i >= 0 ; i--){
    //     for(var j = 0 ; j < delArr.lenth ; j++){
    //         if (i == j){
    //             ds_main4.deleteRow(i);
    //         }
    //     }
    // }

    let row = gr_main4.getFocusedRowIndex();
    if (row > -1) {
      $c.data.deleteRow($p, gr_main4);
    }
  }
};

/**
 * 하역직 Grid 사번조회 팝업
 */
scwin.f_openCommCdPopUp = async function (argFlg) {
  // 선언부
  var rtnList = new Array();
  var pCode = "";
  var pName = "";
  var arrParam = new Array();
  const rowPosition = ds_main4.getRowPosition();

  // 조회 조건 담기
  if (argFlg == 1) {
    pCode = ds_main4.getCellData(rowPosition, "staffNo");
    ds_main4.setCellData(rowPosition, "staffNm", "");
  } else {
    pName = ds_main4.getCellData(rowPosition, "staffNm");
    ds_main4.setCellData(rowPosition, "staffNo", "");
  }
  arrParam[0] = pCode; //사번
  arrParam[1] = pName; //사원명
  arrParam[2] = scwin.parent.txt_hlobranCd.getValue(); //점소코드
  arrParam[3] = scwin.parent.txt_hlobranNm.getValue(); //점소명
  arrParam[4] = ''; //작업장코드
  arrParam[5] = '01'; //직종  (정규직)
  arrParam[6] = '02,D'; //상세직종코드 (하역직)
  arrParam[7] = ''; //직급
  arrParam[8] = scwin.parent.ica_wrkDt.getValue(); //작업예정일자
  arrParam[9] = 'Y'; //배치가능여부
  arrParam[10] = 'T';
  arrParam[11] = '1'; //직종
  arrParam[12] = scwin.parent.acb_shiftClsCd.getValue(); //Shift 구분코드

  // rtnList = window.showModalDialog("/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.jsp", arrParam, "dialogHeight:450px; dialogWidth:530px; resizable=no; help:no; status:no; center=true; "); 	
  let win_url = "/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml";
  let opts = {
    id: "searchEmpNoPop",
    popupName: "사번조회",
    modal: true,
    type: "browserPopup",
    width: 840,
    height: 400,
    title: "사번조회"
  };
  var rtnList = await $c.win.openPopup($p, win_url, opts, arrParam);
  if (rtnList != null && rtnList[1] != undefined) {
    const mJson = ds_main4.getMatchedJSON("staffNo", rtnList[2], true);
    if (mJson.length > 0) {
      await $c.gus.cfAlertMsg($p, "중복하여 입력할 수 없습니다.");
      return;
    }
    ds_main4.setCellData(rowPosition, "staffNo", rtnList[2]); // 사번
    ds_main4.setCellData(rowPosition, "staffNm", rtnList[3]); // 이름
    ds_main4.setCellData(rowPosition, "occpgrdCd", rtnList[4]); // 직급코드
    ds_main4.setCellData(rowPosition, "occpgrdNm", rtnList[5]); // 직급명
    ds_main4.setCellData(rowPosition, "occptypeCd", rtnList[8]); // 직종코드
    ds_main4.setCellData(rowPosition, "occptypeNm", rtnList[9]); // 직종명

    //(0)직종코드		
    //(1)직종명	        
    //(2)인원번호		
    //(3)인원명	                          
    //(4)직급		    
    //(5)직급명		    
    //(6)물류점소코드   
    //(7)물류점소명		
    //(8)상세직종코드	
    //(9)상세직종명		                  
    //(10)배치가능여부	
    //(11)본사계약직여부 
    //(12)연근여부		
  } else {
    ds_main4.setCellData(rowPosition, "staffNo", ""); // 사번
    ds_main4.setCellData(rowPosition, "staffNm", ""); // 이름
    ds_main4.setCellData(rowPosition, "occpgrdCd", ""); // 직급코드
    ds_main4.setCellData(rowPosition, "occpgrdNm", ""); // 직급명
    ds_main4.setCellData(rowPosition, "occptypeCd", ""); // 직종코드
    ds_main4.setCellData(rowPosition, "occptypeNm", ""); // 직종명
  }
};

