scwin.sbm_co_ds_combo1_submit = function (e) {};
scwin.sbm_co_ds_combo1_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    co_ds_combo1.setJSON(e.responseJSON.GAUCE);
    if (co_ds_combo1.getRowCount() > 0) {
      $c.gus.cfEnableObj($p, acb_wrkIndictNo, true);
      $c.gus.cfEnableObj($p, btn_no1, true);
    } else {
      $c.gus.cfEnableObj($p, acb_wrkIndictNo, false);
      $c.gus.cfEnableObj($p, btn_no1, false);
    }
    if (scwin.parent.ds_main2.getRowCount() > 0) {
      if (scwin.parent.ds_main2.getCellData(0, "completeProcYn") == 1) {
        $c.gus.cfEnableObj($p, btn_no1, false);
      } else {
        $c.gus.cfEnableObj($p, btn_no1, true);
      }
    }
    ds_main4.reform();
  }
  ;
};
