/**
 * tableFlag==306이면 로드 직후
    ① 1행 wrkStpCd를 '004'로 강제 설정하고
    ② completeProcYn==0일 때만 데이터를 유지, 아니면 ds_main4를 통째로 비운다.
 */
scwin.ds_main4_onloadcomplete = function () {
  if (ds_main4.getCellData(0, "tableFlag") == 306) {
    ds_main4.setCellData(0, "wrkStpCd", '004');
    // export ??
    // var dataset = ds_main4.ExportData(1,ds_main4.getRowCount(),true);
    // ds_main4.ClearData();
    // if (scwin.parent.ds_main2.NameValue(1,"completeProcYn") == 0) {
    // 	ds_main4.ImportData(dataset);
    // }

    const dataset = ds_main4.getAllJSON().slice(1);
    ds_main4.removeAll();
    ds_main4.reform();
    if (scwin.parent.ds_main2.getCellData(0, "completeProcYn") == 0) {
      ds_main4.setJSON(dataset);
      ds_main4.reform();
    }
  }
  for (let i = 0; i < ds_main4.getTotalRow(); i++) {
    gr_main4.setCellReadOnly(i, "staffNo", true);
    gr_main4.setCellReadOnly(i, "staffNm", true);
  }

  // 노무원/용역직
  ds_main5.setRowPosition(0);
};

/**
 * 그리드 textImage click
 */
scwin.gr_main4_ontextimageclick = function (rowIndex, columnIndex) {
  var colid = gr_main4.getColumnID(columnIndex);
  if (colid == "staffNo") {
    scwin.f_openCommCdPopUp(1);
  } else if (colid == "staffNm") {
    scwin.f_openCommCdPopUp(2);
  }
};

/**
 * 그리드 edit end
 */
scwin.gr_main4_oneditend = function (row, columnIndex, value) {
  const colid = gr_main4.getColumnID(columnIndex);
  if (colid == "staffNo" && ds_main4.getCellData(row, colid) != "") {
    scwin.oldData_staffNo = ds_main4.getCellData(row, colid);
  } else if (colid == "staffNm" && ds_main4.getCellData(row, colid) != "") {
    scwin.oldData_staffNm = ds_main4.getCellData(row, colid);
  }
};

/**
 * 그리드 after edit
 */
scwin.gr_main4_onafteredit = function (row, columnIndex, value) {
  const colid = gr_main4.getColumnID(columnIndex);
  const inputValue = ds_main4.getCellData(row, colid);
  if (inputValue != scwin.oldData_staffNo && inputValue != "") {
    if (colid === "staffNo") {
      scwin.f_openCommCdPopUp(1);
    } else if (colid === "staffNm") {
      scwin.f_openCommCdPopUp(2);
    }
  } else {
    ds_main4.setCellData(row, "staffNo", ""); // 사번
    ds_main4.setCellData(row, "staffNm", ""); // 이름
    ds_main4.setCellData(row, "occpgrdCd", ""); // 직급코드
    ds_main4.setCellData(row, "occpgrdNm", ""); // 직급명
    ds_main4.setCellData(row, "occptypeCd", ""); // 직종코드
    ds_main4.setCellData(row, "occptypeNm", ""); // 직종명
  }
};

/**
 * 그리드 row index change
 */
scwin.gr_main4_onrowindexchange = function (rowIndex, oldRow) {
  scwin.f_defaultCall(rowIndex); // Key 값 수정 X
};

/**
 * Key 값 수정 X
 */
scwin.f_defaultCall = function (rowIndex) {
  //	if(gr_main4.GetColumn() == "staffNo"){

  if (rowIndex) {
    if ("C" == ds_main4.getRowStatus(rowIndex)) {
      gr_main4.setCellReadOnly(rowIndex, "staffNo", false);
      gr_main4.setCellReadOnly(rowIndex, "staffNm", false);
    } else {
      gr_main4.setCellReadOnly(rowIndex, "staffNo", true);
      gr_main4.setCellReadOnly(rowIndex, "staffNm", true);
    }
  } else {
    gr_main4.setColumnReadOnly("staffNo", true);
    gr_main4.setColumnReadOnly("staffNm", true);
  }

  //	}
};

/**
 * 그리드 cell click
 */
scwin.gr_main4_oncellclick = async function (rowIndex, columnIndex, columnId) {
  if (columnId == "cfmanYn" && ds_main4.getCellData(rowIndex, columnId) == "1") {
    const cfmanYn = ds_main4.getColSum("cfmanYn");
    if (cfmanYn > 1) {
      await $c.gus.cfAlertMsg($p, "Chief 포맨은 두명이상 선택할 수 없습니다.");
      ds_main4.setCellData(rowIndex, "cfmanYn", "");
      return;
    }
  }
};

